IF (NOT(target=0)) THEN
	allocateControllerMotor := target;
	RETURN;
END_IF

allocateControllerMotor := __NEW(ControllerMotor);
_countControllerMotor := _countControllerMotor + 1;

IF (allocateControllerMotor=0) THEN
	gCodeErrorHandler(pMessage:='Memory allocation failed for <ControllerMotor>');
END_IF

IF (__ISVALIDREF(target)) THEN
	allocateControllerRotaryEncoderRange REF= target;
	RETURN;
END_IF

ptr := __NEW(ControllerRotaryEncoderRange);
_countControllerRotaryEncoderRange := _countControllerRotaryEncoderRange + 1;

IF (ptr=0) THEN
	gCodeErrorHandler(pMessage:='Memory allocation failed for <ControllerRotaryEncoderRange>');
	allocateControllerRotaryEncoderRange REF= _defaultControllerRotaryEncoderRange;
	RETURN;
END_IF

allocateControllerRotaryEncoderRange REF= ptr^;

