SUPER^.initialize();
SubSystem := cSubsystemSpreader;

lPeripheral.initialize();

lAlarmCANOpenSlaveModulation.registerServer(gSystemApollo.Travel.Interlock);
// lAlarmCANOpenSlaveNotOperational.Override := TRUE; //foobar

lStartSystemStateScope := t_system_state.cSystemStateGoOperational;
lOperationalSystemStateScopeLower := t_system_state.cSystemStateOperational;
lModulationSystemStateScope := t_system_state.cSystemStateOperational;

lTransmitTimer.initialize();
lTransmitTimer.Period := cTransmitPeriod;
lTransmitTimer.Enable := TRUE;

// lEnableValidTransmissions := TRUE;
lEnableDetectionTPDO := TRUE;
lEnableNMTDetectionTPDO := TRUE;
lEnableNMTOverrideTPDO := TRUE;

lTwistlocksLockCommand.Value := gSystemApollo.UInterface.TwistlockLock;
lTwistlocksUnlockCommand.Value := gSystemApollo.UInterface.TwistlockUnlock;

lSideshiftABCommand.Value := gSystemApollo.UInterface.SideshiftAB;
lSideshiftCDCommand.Value := gSystemApollo.UInterface.SideshiftCD;

IF (lTelescopingEnabled.Value) THEN
	IF (lTelescopingExtendAutoCommand.Value) THEN
		lTelescopingAutoCommand.Value := TRUE;
		lTelescopingExtendCommand.Value := TRUE;
		lTelescopingRetractCommand.Value := FALSE;
	END_IF

	IF (lTelescopingRetractAutoCommand.Value) THEN
		lTelescopingAutoCommand.Value := TRUE;
		lTelescopingExtendCommand.Value := FALSE;
		lTelescopingRetractCommand.Value := TRUE;
	END_IF

	IF (lTelescopingExtendCommand.Value) THEN
		lTelescopingAutoCommand.Value := FALSE;
		lTelescopingExtendCommand.Value := TRUE;
		lTelescopingRetractCommand.Value := FALSE;
	END_IF

	IF (lTelescopingRetractCommand.Value) THEN
		lTelescopingAutoCommand.Value := FALSE;
		lTelescopingExtendCommand.Value := FALSE;
		lTelescopingRetractCommand.Value := TRUE;
	END_IF
ELSE
	lTelescopingAutoCommand.Value := FALSE;
	lTelescopingExtendCommand.Value := FALSE;
	lTelescopingRetractCommand.Value := FALSE;
END_IF

lTransmitTimer.operator();
IF (lTransmitTimer.Expired) THEN
	lTransmitTimer.reset();

	// momentary commands
	lTelescopingEnableCommand.Value := FALSE;
	lTelescopingExtendAutoCommand.Value := FALSE;
	lTelescopingRetractAutoCommand.Value := FALSE;
END_IF

lPeripheral.SupplementaryCommand := 0;

SUPER^.operator();	

lPeripheral.operator();

IF (NOT(ValidTransmissions)) THEN
	// lBrakeDisengaged.Value := FALSE; foobar	
	// RETURN;
END_IF

//foobar error handling

lFaultHydraulicFilter.InputReference REF= supplementaryState;
lBrakeDisengaged.InputReference REF= supplementaryState;
lFaultBrake.InputReference REF= supplementaryState;

lHydraulicPressure.InputReference REF= hydraulicPressure;
lHydraulicTemperature.InputReference REF= hydraulicTemperature;
lPumpCurrent.InputReference REF= pumpCurrent;
lPumpBatteryCurrent.InputReference REF= pumpBatteryCurrent;
lPumpBatteryVoltage.InputReference ref= pumpBatteryVoltage;
lPumpVelocity.InputReference ref= pumpVelocity;
lPumpMotorTemperature.InputReference ref= pumpMotorTemperature;
lPumpControllerTemperature.InputReference ref= pumpControllerTemperature;
lPumpState.InputReference REF= pumpState;
lPumpAllow.InputReference REF= pumpState;
lPumpRunning.InputReference REF= pumpState;
lPumpDirectOn.InputReference REF= pumpState;
lPumpPressureOK.InputReference REF= pumpState;
lPumpAlarm.InputReference REF= pumpAlarm;

