SUPER^.operator();

IF (lEnableRelaxed) THEN
	lTransform.InnerRegion := cInnerRegionRelaxed;
	lTransform.OuterRegion := cOuterRegionRelaxed;
	lTransform.InnerValue := cInnerValueRelaxed;
	lTransform.OuterValue := cOuterValueRelaxed;
ELSE
	lTransform.InnerRegion := cInnerRegion;
	lTransform.OuterRegion := cOuterRegion;
	lTransform.InnerValue := cInnerValue;
	lTransform.OuterValue := cOuterValue;
END_IF

IF (override) THEN
	RETURN;
END_IF

clear();

lPosition := (gSystemApollo.CANOpenMasterDriveApollo.WinchAngleA.PositionObject.Value +
	gSystemApollo.CANOpenMasterDriveApollo.WinchAngleB.PositionObject.Value +
	gSystemApollo.CANOpenMasterDriveApollo.WinchAngleC.PositionObject.Value +
	gSystemApollo.CANOpenMasterDriveApollo.WinchAngleD.PositionObject.Value) / 4.0;

IF (NOT(gSystemApollo.Spreader.TwistlocksReadyState)) THEN
	lAllowAdditionalMovement := (ABS(lPosition - lResetPosition) < lPositionLimit);

	IF (NOT(lAllowAdditionalMovement)) THEN
		lInterlockState:=cInterlockStateError;
		lScalingPositive := 0.0;
		lThresholdPositive := 0.0;
		lScalingNegative := 0.0;
		lThresholdNegative := 0.0;

		trigger(FALSE);
	END_IF
ELSE
	lResetPosition := lPosition;
END_IF

IF (Laden) THEN
	lFunctionSlowFactor := lSlowFactorLaden;
ELSE
	lFunctionSlowFactor := lSlowFactorUnladen;
END_IF

SUPER^.checks();

