lBalanceAB.Name := 'BalanceAB';
lBalanceAB.SubSystem := cSubsystemLift;
registerNonOperational(ADR(lBalanceAB));

lBalanceAD.Name := 'BalanceAD';
lBalanceAD.SubSystem := cSubsystemLift;
registerNonOperational(ADR(lBalanceAD));

SUPER^.initialize();
SubSystem := cSubsystemLift;

lFunctionalMode := cFunctionalModeLift;

lRegisterUMFSPrimary := TRUE;
lRegisterUMFSAuxilliary := TRUE;
lRegisterUMFSSecondary := TRUE;

lRegisterActive := TRUE;
lRegisterOperatingMode := TRUE;

lEnabled := TRUE;
lEnableOnlyOnActiveAllow := FALSE;
lEnableUMFSCheck := TRUE;

lEnableOperatingModeSlow := TRUE;
lEnableUInterfaceSlow := FALSE;
lEnableFunctionSlow := TRUE;

lInput.InputAsPercentage := gSystemApollo.UInterface.Lift;
lInput.operator();

balanceAB := gSystemApollo.UInterface.LiftBalanceAB;
IF (balanceAB>0) THEN
	balanceAB := MIN(balanceAB * lBalanceABFactor,1.0);
END_IF
IF (balanceAB<0) THEN
	balanceAB := MAX(balanceAB * lBalanceABFactor,-1.0);
END_IF
lBalanceAB.Value := balanceAB;
lBalanceAB.operator();

balanceAD := gSystemApollo.UInterface.LiftBalanceAD;
IF (balanceAD>0) THEN
	balanceAD := MIN(balanceAD * lBalanceADFactor,1.0);
END_IF
IF (balanceAD<0) THEN
	balanceAD := MAX(balanceAD * lBalanceADFactor,-1.0);
END_IF
lBalanceAD.Value := balanceAD;
lBalanceAD.operator();

lScalingA := 1.0;
lScalingB := 1.0;
lScalingC := 1.0;
lScalingD := 1.0;

IF ((lEnableBalanceAB) AND (lBalanceAB.Value<0)) THEN
	lScalingB := lScalingB*ABS(1+lBalanceAB.Value);
	lScalingC := lScalingC*ABS(1+lBalanceAB.Value);
END_IF
IF ((lEnableBalanceAB) AND (lBalanceAB.Value>0)) THEN
	lScalingA := lScalingA*ABS(1-lBalanceAB.Value);
	lScalingD := lScalingD*ABS(1-lBalanceAB.Value);
END_IF

IF (lBalanceAD.Value<0) THEN
	lScalingA := lScalingA*ABS(1+lBalanceAD.Value);
	lScalingB := lScalingB*ABS(1+lBalanceAD.Value);
END_IF
IF (lBalanceAD.Value>0) THEN
	lScalingC := lScalingC*ABS(1-lBalanceAD.Value);
	lScalingD := lScalingD*ABS(1-lBalanceAD.Value);
END_IF

lLaden := gSystemApollo.CANOpenMasterDriveApollo.Spreader.Laden;

SUPER^.operator();

