SUPER^.initialize();
SubSystem := cSubsystemLift;

lTargetPosition.initialize();

lPositionA REF= gSystemApollo.CANOpenMasterDriveApollo.WinchAngleA.PositionObject;
lPositionB REF= gSystemApollo.CANOpenMasterDriveApollo.WinchAngleB.PositionObject;
lPositionC REF= gSystemApollo.CANOpenMasterDriveApollo.WinchAngleC.PositionObject;
lPositionD REF= gSystemApollo.CANOpenMasterDriveApollo.WinchAngleD.PositionObject;

SUPER^.running();

IF (lState<>cProgMovStateRunning) THEN
	RETURN;
END_IF

lScaling := (UINT_TO_REAL(lTimeStep)/UINT_TO_REAL(lAccelerationAsTimeStep));
lScaling := MIN(1.0,lScaling);

lPosition := (lPositionA.Value + lPositionB.Value + lPositionC.Value + lPositionD.Value)/4.0;

lScaling := (lTargetPosition.Value - lPosition)/lDecelerationAsPercentage * lScaling;
lScaling := MIN(1.0,lScaling);
lScaling := MAX(-1.0,lScaling);

IF (ABS(lScaling)<lPositionZeroThreshold) THEN
	lScaling := 0.0;
	lPositionAchieved := TRUE;
END_IF

gSystemApollo.Lift.EnableInputSecondary := TRUE;
gSystemApollo.Lift.InputSecondaryValue := LiftThrottle * lScaling * lSign;

gSystemApollo.lLiftSynchronousInterlock.tighten();

InterruptCondition := FALSE;

IF (gSystemApollo.UInterface.LiftJoystickInputPresent) THEN
	InterruptCondition := TRUE;	
END_IF

Name := 'Travel';

lVREnableNullOnSteeringModeChange.initializeValueReference(lEnableNullOnSteeringModeChange,THIS,'NullOnStrModChg');
lVREnableNullOnSteeringState.initializeValueReference(lEnableNullOnSteeringState,THIS,'NullOnStrStt');

_ThrottleA.Name := 'ThrottleA';
MovementA.Throttle REF= _ThrottleA;
_ThrottleA.ControllerMotor REF= gSystemApollo.CANOpenMasterDriveApollo.TransC;
registerNonOperational(ADR(_ThrottleA));

_ThrottleB.Name := 'ThrottleB';
MovementB.Throttle REF= _ThrottleB;
_ThrottleB.ControllerMotor REF= gSystemApollo.CANOpenMasterDriveApollo.TransD;
registerNonOperational(ADR(_ThrottleB));

SUPER^.initialize();

lFunctionalMode := cFunctionalModeDefault;

lRegisterUMFSPrimary := TRUE;
lRegisterUMFSAuxilliary := TRUE;
lRegisterUMFSSecondary := TRUE;

lRegisterActive := TRUE;
lRegisterOperatingMode := TRUE;

lEnabled := TRUE;
lEnableOperatingModeSlow := TRUE;
lEnableOnlyOnActiveAllow := FALSE;
lEnableUMFSCheck := TRUE;

lInput.InputAsPercentage := gSystemApollo.UInterface.Travel;
lInput.operator();

IF (lInput.Value<>0) THEN
	lInput.Value := MIN(ABS(lInput.Value),gSystemApollo.Steering.Mode.TravelThrottleThreshold)*lInput.Value/ABS(lInput.Value);
END_IF

IF ((gSystemApollo.Steering.ModeChange) AND 
	(lEnableNullOnSteeringModeChange)) THEN
	lInput.Value := 0;
	//gMessageManager.register(lCode:=cMCAdviseSteerOverideTravelLock);
END_IF

IF ((gSystemApollo.Steering.State=cAdjustStateError) AND 
	(lEnableNullOnSteeringState)) THEN
	IF (lEnableSteerStateErrorThrottle) THEN
		lInput.Value := MIN(ABS(lInput.Value),lSteerStateErrorThrottleThreshold)*lInput.Value/ABS(lInput.Value);
		//gMessageManager.register(lCode:=cMCAdviseSteerOverideTravelLock);
	ELSE
		lInput.Value := 0;
		//gMessageManager.register(lCode:=cMCAdviseSteerOverideTravelLock);		
	END_IF
END_IF

lScalingA := gSystemApollo.Steering.WheelC.WheelVelocityFactor * gSystemApollo.Steering.WheelC.WheelDirection;
lScalingB := gSystemApollo.Steering.WheelD.WheelVelocityFactor * gSystemApollo.Steering.WheelD.WheelDirection;

SUPER^.operator();

IF (((lInputProcessed<>0) OR
	(lEnableAlwaysActiveOnOperational)) AND
	(gSystemApollo.SystemState.State=cSystemStateOperational)) THEN
	lActiveState.registerActive();
END_IF
lActiveState.operator();

gSystemApollo.CANOpenMasterDriveApollo.Spreader.BrakeDisengageCommand := (lActiveState.IsActive);

// wait until brake has engaged
// evaluating whether to use this mechanism or a timeout on exitOperational, as this state should be protected with a timeout
// deprecated until spreader is reliable in reporting brakeDisengaged status
IF (gSystemApollo.SystemState.State=cSystemStateExitOperational) THEN
	IF (gSystemApollo.CANOpenMasterDriveApollo.Spreader.BrakeDisengaged) THEN
		gSystemApollo.SystemState.transitionAllowDown(cSystemStateExitOperational,ADR(lCausalWaitingForBrakeDisengaged),lCausalWaitingForBrakeDisengaged.Override);
	END_IF
END_IF

// travel case, no explicit holding as stationary
// brake is report as disengaged though no guarantee
// note that input could be zero however
IF ((lActiveState.Allow) AND (gSystemApollo.CANOpenMasterDriveApollo.Spreader.BrakeDisengaged)) THEN
	DerivedThrottleA.ControllerMotor.HoldStationary := FALSE;
	DerivedThrottleB.ControllerMotor.HoldStationary := FALSE;
	DerivedThrottleC.ControllerMotor.HoldStationary := FALSE;
	DerivedThrottleD.ControllerMotor.HoldStationary := FALSE;

	RETURN;
END_IF

// pre state or brake may be in unknown state
// force stationary
IF (lActiveState.IsActive) THEN
	DerivedThrottleA.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleB.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleC.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleD.ControllerMotor.HoldStationary := TRUE;

	lInputProcessed := 0.0;
	Diagnostic := cMovementDiagnosticBrakeEngaged;

	RETURN;
END_IF

// brake is reported as released, no guarantee that it really is
// can assume that input is zero
// force stationary
// deprecated because keeping the enable bit true does not necessarily force the controller to keep the motor stationary
// it is defined by the aux time parameter in the controller
// assuming that the hold spikes are not being used to keep the controller engaged which is anyway costly in energy
(*IF (gSystemApollo.CANOpenMasterDriveApollo.Spreader.BrakeDisengaged) THEN
	DerivedThrottleA.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleB.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleC.ControllerMotor.HoldStationary := TRUE;
	DerivedThrottleD.ControllerMotor.HoldStationary := TRUE;

	lInputProcessed := 0.0;
	Diagnostic := cMovementDiagnosticBrakeDisengaged;

	RETURN;
END_IF*)

// catchall - clear holding stationary
DerivedThrottleA.ControllerMotor.HoldStationary := FALSE;
DerivedThrottleB.ControllerMotor.HoldStationary := FALSE;
DerivedThrottleC.ControllerMotor.HoldStationary := FALSE;
DerivedThrottleD.ControllerMotor.HoldStationary := FALSE;

IF (lInput.Value<>0) THEN
	IF (gSystemApollo.Steering.Mode.TravelThrottleThreshold=0.0) THEN
		lInputNulled := TRUE;
		Diagnostic := cMovementDiagnosticThreshold;
	END_IF
	InputThresholdAbsolute := ABS(gSystemApollo.Steering.Mode.TravelThrottleThreshold);
END_IF

IF ((gSystemApollo.Steering.ModeChange) AND 
	(lEnableNullOnSteeringModeChange)) THEN
	Diagnostic := cMovementDiagnosticSteeringModeChange;
	lInputNulled := TRUE;
	//gMessageManager.register(lCode:=cMCAdviseSteerOverideTravelLock); //foobar no further notification
END_IF

lSteerAdjustTimer.operator();
IF ((gSystemApollo.Steering.State=cAdjustStateError)
	AND (lEnableNullOnSteeringState)) THEN
	IF (lSteerAdjustTimer.Expired) THEN	
		IF (lEnableSteerStateErrorThrottle) THEN
			lInput.Value := MIN(ABS(lInput.Value),lSteerStateErrorThrottleThreshold)*lInput.Value/ABS(lInput.Value);
		ELSE
			lInputNulled := TRUE;
		END_IF

		Diagnostic := cMovementDiagnosticSteeringState;
		//gMessageManager.register(lCode:=cMCAdviseSteerOverideTravelLock); // foobar notification
	END_IF
ELSE
	lSteerAdjustTimer.reset();
END_IF

IF (gSystemApollo.CANOpenMasterDriveApollo.Spreader.Laden) THEN
	lFunctionSlowFactor := lSlowFactorLaden;
ELSE
	lFunctionSlowFactor := lSlowFactorUnladen;
END_IF

