SUPER^.initialize();
SubSystem := cSubsystemSpreader;

lTwistlockACurrentStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockACurrentState;
lTwistlockALoweredStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockALoweredState;
lTwistlockAReadyStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockAReadyState;

lTwistlockACurrentState := lTwistlockACurrentStateCandidate;
lTwistlockALoweredState.Value := lTwistlockALoweredStateCandidate;
lTwistlockAReadyState := lTwistlockAReadyStateCandidate;

lTwistlockBCurrentStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockBCurrentState;
lTwistlockBLoweredStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockBLoweredState;
lTwistlockBReadyStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockBReadyState;

lTwistlockBCurrentState := lTwistlockBCurrentStateCandidate;
lTwistlockBLoweredState.Value := lTwistlockBLoweredStateCandidate;
lTwistlockBReadyState := lTwistlockBReadyStateCandidate;

lTwistlockCCurrentStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockCCurrentState;
lTwistlockCLoweredStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockCLoweredState;
lTwistlockCReadyStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockCReadyState;

lTwistlockCCurrentState := lTwistlockCCurrentStateCandidate;
lTwistlockCLoweredState.Value := lTwistlockCLoweredStateCandidate;
lTwistlockCReadyState := lTwistlockCReadyStateCandidate;

lTwistlockDCurrentStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockDCurrentState;
lTwistlockDLoweredStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockDLoweredState;
lTwistlockDReadyStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockDReadyState;

lTwistlockDCurrentState := lTwistlockDCurrentStateCandidate;
lTwistlockDLoweredState.Value := lTwistlockDLoweredStateCandidate;
lTwistlockDReadyState := lTwistlockDReadyStateCandidate;

lTwistlocksReadyStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlocksReadyState;
lTwistlocksReadyState := lTwistlocksReadyStateCandidate;

lTwistlocksCurrentStateCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlocksCurrentState;
lTwistlocksCurrentState := lTwistlocksCurrentStateCandidate;
IF (lTwistlocksCurrentState=t_lock_state.cLockStateNone) THEN
	lTwistlocksCurrentState := t_lock_state.cLockStatePartial;
END_IF

SUPER^.operator();

lTwistlocksEnabledCandidate := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlocksEnabled;
lTwistlocksEnabled := ((lTwistlocksEnabledCandidate) OR
	((lTwistlockALoweredState.Value) AND
	(lTwistlockBLoweredState.Value) AND
	(lTwistlockCLoweredState.Value) AND
	(lTwistlockDLoweredState.Value)));

SUPER^.operator();

IF (NOT(lEnable)) THEN
	RETURN;
END_IF

// robustness measures:
// traveling and one false/on (sensor false positive or container moves): masked until lowered to limit, further upon context reset
// lowering and one false/off (sensor fails to detect): allows further lowering to limit, warning as further upon context reset possible
// lowered but chassis/stack movement or signaled too early or pulse raised: masked until lowered to limit

// average is considered more robust than per corner specific 
lPosition := (lPositionA.Value + lPositionB.Value) / 2.0;

// foobar error handling notification

IF ((lTwistlockALoweredStateCandidate) AND (lTwistlockBLoweredStateCandidate)) THEN
	lAllowAdditionalMovement := ((lResetPosition - lPosition) < lPositionLimit);

	lTwistlockALoweredState.Value := NOT(lAllowAdditionalMovement);
	lTwistlockBLoweredState.Value := NOT(lAllowAdditionalMovement);

	RETURN;
END_IF

IF (((NOT(lTwistlockALoweredStateCandidate)) AND (lTwistlockBLoweredStateCandidate)) OR	
	((NOT(lTwistlockBLoweredStateCandidate)) AND (lTwistlockALoweredStateCandidate))) THEN
	IF (lContext.Value>=lContextReset) THEN		
		lResetPosition := lPosition;
	END_IF

	lAllowAdditionalMovement := ((lResetPosition - lPosition) < lPositionLimit);

	lTwistlockALoweredState.Value := NOT(lAllowAdditionalMovement);
	lTwistlockBLoweredState.Value := NOT(lAllowAdditionalMovement);

	RETURN;
END_IF

lResetPosition := lPosition;

lTwistlockALoweredState.Value := lTwistlockALoweredStateCandidate;
lTwistlockBLoweredState.Value := lTwistlockBLoweredStateCandidate;

SUPER^._operator();

CASE lUIEventCode OF
	cUIEventCodeToggleSpreaderConfiguration:
		gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingEnableCommand := TRUE;

	cUIEventCodeSpreaderExtensionAutoCommand:
		gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingExtendAutoCommand := TRUE;

	cUIEventCodeSpreaderRetractionAutoCommand:
		gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingRetractAutoCommand := TRUE;
END_CASE

lPackSystem.initializePackSystemPLC(THIS^);
lPackUICommand.initializePackUICommandPLC(THIS^);
lPackReportable.initializePackReportablePLC(reportableChannelUIR);

initializeUInterfacePLC(lPackSystem,
	lPackMovement,
	lPackReportable,
	lPackSpreader,
	lPackUICommand,
	packProvider);

UInterfaceA REF= lUInterfaceRadio;
UInterfaceB REF= lUInterfaceCabin;

registerNonOperational(ADR(lUInterfaceRadio));
registerNonOperational(ADR(lUInterfaceCabin));

SUPER^.initialize();

lUInterfaceRadio.UInterfaceId := t_ui_id.cUIIdA;
lUInterfaceCabin.UInterfaceId := t_ui_id.cUIIdB;

lSideShiftActive := ((gSystemApollo.SystemState.State=cSystemStateOperational) AND
	((gSystemApollo.CANOpenMasterDriveApollo.Spreader.SideshiftABCommand<>0.0) OR
	(gSystemApollo.CANOpenMasterDriveApollo.Spreader.SideshiftCDCommand<>0.0)));

lTwistlocksState := gSystemApollo.Spreader.TwistlocksCurrentState;

lStateA := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockACurrentState;
lLoweredA := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockALoweredState;
lStateB := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockBCurrentState;
lLoweredB := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockBLoweredState;
lStateC := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockCCurrentState;
lLoweredC := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockCLoweredState;
lStateD := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockDCurrentState;
lLoweredD := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TwistlockDLoweredState;

lExtensionState := t_spreader_extension_state.cSpreaderExtensionState6m;

lSpreaderOperationEnabled := gSystemApollo.Spreader.TwistlocksEnabled;
lSpreaderOperationActive := ((gSystemApollo.Spreader.TwistlockALoweredState) OR
	(gSystemApollo.Spreader.TwistlockBLoweredState) OR
	(gSystemApollo.Spreader.TwistlockCLoweredState) OR
	(gSystemApollo.Spreader.TwistlockDLoweredState));

lSpreaderConfigurationOptionEnabled := ((gSystemPrimary.SystemState.State=cSystemStateOperational) AND
	(gSystemApollo.OperatingMode.Mode>cOperatingModeUnparking) AND
	(lTwistlocksState=cLockStateUnlocked) AND
	(NOT(lLoweredA)) AND
	(NOT(lLoweredB)) AND
	(NOT(lLoweredC)) AND
	(NOT(lLoweredD)));
lSpreaderConfigurationEnabled := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingEnabled;
lSpreaderConfigurationActive := gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingActive;
lSpreaderConfigurationExtending := ((gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingActive) AND (gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingExtendCommand));
lSpreaderConfigurationRetracting := ((gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingActive) AND (gSystemApollo.CANOpenMasterDriveApollo.Spreader.TelescopingRetractCommand));

UInterfaceA REF= lUInterfaceRadioA;
UInterfaceB REF= lUInterfaceRadioB;

lUInterfaceRadioA.Name := 'RadioA';
registerNonOperational(ADR(lUInterfaceRadioA));

lUInterfaceRadioB.Name := 'RadioB';
registerNonOperational(ADR(lUInterfaceRadioB));

SUPER^.initialize();

lUInterfaceRadioA.UInterfaceId := t_ui_id.cUIIdA;
lUInterfaceRadioB.UInterfaceId := t_ui_id.cUIIdB;

lPackSystem.initializePackSystemPLC(THIS^);
lPackUICommand.initializePackUICommandPLC(THIS^);
lPackReportable.initializePackReportablePLC(reportableChannelUIR);

initializeUInterfacePLC(lPackSystem,
	lPackMovement,
	lPackReportable,
	lPackSpreader,
	lPackUICommand,
	packProvider);
